import Foundation

func solve(nums: Array<Int64>) -> Int64 {
    let n = nums.count
    var maxSum: Int64 = 0

    // Iterate all possible subsets for B (AND part)
    for mask in 0..<(1 << n) {
        var andB: Int64 = ~0 // Initial value for AND (all bits set)
        var xorA: Int64 = 0
        var xorC: Int64 = 0

        for i in 0..<n {
            if mask & (1 << i) != 0 {
                // Element is in B
                andB &= nums[i]
            }
        }

        // Now find the best A and C for this B
        // A and C are the remaining elements not in B
        // We need to partition the remaining elements into A and C to maximize xorA + xorC

        let remainingIndices = (0..<n).filter { mask & (1 << $0) == 0 }
        let m = remainingIndices.count

        // Try all possible ways to split remaining elements into A and C
        for aMask in 0..<(1 << m) {
            var currentXorA: Int64 = 0
            var currentXorC: Int64 = 0

            for j in 0..<m {
                let num = nums[remainingIndices[j]]
                if aMask & (1 << j) != 0 {
                    currentXorA ^= num
                } else {
                    currentXorC ^= num
                }
            }

            let total = currentXorA + andB + currentXorC
            if total > maxSum {
                maxSum = total
            }
        }
    }

    return maxSum
}
